          </div>
          <div className="col-md-6">
            <ul className="mb-0">
              <li><strong>Email format</strong> must be valid</li>
              <li><strong>Phone number</strong> should be exactly 10 digits</li>
              <li><strong>Address</strong> must be at least 10 characters long</li>
            </ul>
